import React, { useEffect, useState } from 'react'
import { Modal, Row, Col, Input, Select, Card, Form, Button, Radio } from 'antd';
import '../../../CSS/AddEditFormModalStyle.css'
import { containerConstantsService } from '../../../utils/containerconstants/ContainerConstants';
import { OPERATION, PARCEL_SHOP_MASTER_FORM_ELEMENTS, PARTY_MASTER_FORM_ELEMENTS, MASTER_DATA_INDEX, MASTER_DATA_STRING_CONSTANTS, PARTY_MASTER_TYPE, STATUS, LEFT_TABS, PARTY_MASTER_BOOLEAN_OPTIONS_LIST } from '../../../utils/constants';
import { isEqual, toUpper, upperFirst, toLower, isEmpty } from 'lodash';
import { savePartyMaster, saveParcelShopMaster } from './hooks/APIConfig/MasterDataTabCardAction';
import {notifyResponseMessage} from '../../commoncomponent/NotificationComponent/notifyResponseMessage';

const containerConstants = containerConstantsService.getInstance();
const { Item } = Form
const {Option} = Select;
const AddEditFormModal = ({ showModalDialogForm, ...otherProps }) => {
    const [showLoading,setShowLoading] = useState(false);
    const [formData, setFormData] = useState({});
    const [validation, setValidation] = useState({});
    const [disableFields, setDisableFields] = useState({});

    useEffect(() => {
        if (showModalDialogForm.visible && isEqual(showModalDialogForm.operation, OPERATION.EDIT)) {
            const dataObj = showModalDialogForm.data;
            if (showModalDialogForm.form === LEFT_TABS.PARTY_MASTER_TABPANE) {
                setFormData({ ...dataObj, [MASTER_DATA_INDEX.ACCEPT_OVERAGE_PICKUP]: upperFirst(dataObj[MASTER_DATA_INDEX.ACCEPT_OVERAGE_PICKUP]), [MASTER_DATA_INDEX.BRAND_EXPERIENCE]: upperFirst(dataObj[MASTER_DATA_INDEX.BRAND_EXPERIENCE]) });
                setDisableFields({ [MASTER_DATA_INDEX.MERCHANT_CODE]: true })
            } else {
                setFormData({ ...dataObj })
                setDisableFields({ [MASTER_DATA_INDEX.CODE]: true })
            }
        }
    }, [showModalDialogForm]);

    const isEmptyData = () => {
        let emptyCount = 0
        const formElements = showModalDialogForm.form === LEFT_TABS.PARTY_MASTER_TABPANE ?
            PARTY_MASTER_FORM_ELEMENTS : PARCEL_SHOP_MASTER_FORM_ELEMENTS;
        formElements.forEach(({ name, isRequired }) => {
            if (!formData[name] && isRequired) {
                emptyCount++;
                setValidation(prev => ({ ...prev, [name]: 1 }));
            }
        })
        return !emptyCount ? false : true;
    }

    const handleClickOk = () => {
        if (!isEmptyData(formData)) {
        setShowLoading(true);
            if (showModalDialogForm.form === LEFT_TABS.PARTY_MASTER_TABPANE) {
                onSavePartyMaster();
            } else if (showModalDialogForm.form === LEFT_TABS.PARCEL_SHOP_MASTER_TABPANE) {
                onSaveParcelShopMaster();
            }
        }
    }

    const onSavePartyMaster = () => {
        savePartyMaster(formData)
            .then(response => {
                setShowLoading(false);
                if (response && response.status === 200) {
                    if (toUpper(response.data?.status) === STATUS.FAILED) {
                        notifyResponseMessage(STATUS.ERROR,upperFirst(response.data?.message));
                        setValidation(prev => ({ ...prev, [MASTER_DATA_INDEX.ERROR_MSG]: upperFirst(response.data?.message) }));
                    } else {
                        notifyResponseMessage(STATUS.SUCCESS,upperFirst(response.data?.message));
                        handleClickCancel();
                    }
                }else if(response && response.response && response.response.data && response.response.data.message){
                    notifyResponseMessage(STATUS.ERROR,response.response.data.message);
                }
            })
            .catch(error => {
                setShowLoading(false);
                notifyResponseMessage(STATUS.ERROR,error.message);
            });
    }

    const onSaveParcelShopMaster = () => {
        setShowLoading(true);
        saveParcelShopMaster(formData)
            .then(response => {
                setShowLoading(false);
                if (response && response.status === 200) {
                    if (toUpper(response.data?.status) === STATUS.FAILED) {
                        notifyResponseMessage(STATUS.ERROR,upperFirst(response.data?.message));
                        setValidation(prev => ({ ...prev, [MASTER_DATA_INDEX.ERROR_MSG]: upperFirst(response.data?.message) }));
                    } else {
                        notifyResponseMessage(STATUS.SUCCESS,upperFirst(response.data?.message));
                        handleClickCancel();
                    }
                }
            })
            .catch(error => {
                setShowLoading(false);
                notifyResponseMessage(STATUS.ERROR,error.message);
            });
    }

    const handleClickCancel = () => {
        setShowLoading(false);
        setFormData({})
        setValidation({})
        setDisableFields({})
        otherProps.setShowModalDialogForm({ visible: false, title: '', okText: '' })
    }

    const updateFieldValue = (e, name) => {
        setFormData({ ...formData, [name]: e.target.value });
        validation[name] && delete validation[name];
        validation[MASTER_DATA_INDEX.ERROR_MSG] && delete validation[MASTER_DATA_INDEX.ERROR_MSG];
    }

    const getRowWithInputElementJsx = (label, name) => {
        return (
            <Row>
                <Col span={9}>{label}</Col>
                <Col span={(showModalDialogForm.form === LEFT_TABS.PARTY_MASTER_TABPANE) ? 14 : 15}>
                    <Item
                        validateStatus={validation[name] ? 'error' : null}
                        help={validation[name] ? containerConstants.formatString(containerConstants.REQUIRED_VALIDATION_MSG, toLower(label)) : null}>
                        <Input name={name} value={formData[name]} disabled={disableFields[name]} placeholder={MASTER_DATA_STRING_CONSTANTS.PLACEHOLDER} onChange={(e) => updateFieldValue(e, name)} />
                    </Item>
                </Col>
            </Row>
        );
    }

    const getRowWithSelectElementJsx = (label, name, options) => {
        return (
            <Row>
                <Col span={9}>{label}</Col>
                <Col span={(showModalDialogForm.form === LEFT_TABS.PARTY_MASTER_TABPANE) ? 14 : 15}>
                    <Item
                        validateStatus={validation[name] ? 'error' : null}
                        help={validation[name] ? containerConstants.formatString(containerConstants.REQUIRED_VALIDATION_MSG, toLower(label)) : null}>
                        <Select
                            onChange={value => {
                                if (value) {
                                    setFormData({ ...formData, [name]: value })
                                    validation[name] && delete validation[name];
                                }
                            }}
                            placeholder={containerConstants.formatString(containerConstants.SELECT)}
                            value={formData[name]}
                        >
                            {options.map(option => <Option value={option}>{option}</Option>)}
                        </Select>
                    </Item>
                </Col>
            </Row>
        );
    }

    const getRowWithRadioElementJsx = (label, name) => {
        return (
            <Row>
                <Col span={9}>{label}</Col>
                <Col span={(showModalDialogForm.form === LEFT_TABS.PARTY_MASTER_TABPANE) ? 14 : 15}>
                    <Item
                        validateStatus={validation[name] ? 'error' : null}
                        help={validation[name] ? containerConstants.formatString(containerConstants.REQUIRED_VALIDATION_MSG, toLower(label)) : null}
                    >
                        <Radio.Group className='flex justify-space-btw' style={{ width: '230px', fontWeight: 'normal' }}
                            options={PARTY_MASTER_BOOLEAN_OPTIONS_LIST} value={formData[name]}
                            onChange={e => {
                                setFormData({ ...formData, [name]: e.target.value });
                                validation[name] && delete validation[name];
                            }}
                        />
                    </Item>
                </Col>
            </Row>
        );
    }

    return (
        <div>
            <Modal
                title={showModalDialogForm.title}
                className='master-data-form-modal'
                centered={true}
                visible={showModalDialogForm.visible}
                onCancel={handleClickCancel}
                footer={[
                    <span className='ant-form-item-explain-error' style={{ float: 'left' }}>{validation[MASTER_DATA_INDEX.ERROR_MSG] && validation[MASTER_DATA_INDEX.ERROR_MSG]}</span>,
                    <Button key="cancel" style={{ color: '#727272', border: 0 }} onClick={handleClickCancel}>
                        {containerConstants.formatString(containerConstants.CANCEL)}
                    </Button>,
                    <Button loading = {showLoading} key="submit" type="primary" style={{ color: '#FFFFFF', opacity: !isEmpty(validation) && '0.5' }} onClick={handleClickOk}>
                        {showModalDialogForm.okText}
                    </Button>
                ]}
            >
                {showModalDialogForm.form === LEFT_TABS.PARTY_MASTER_TABPANE &&
                    <Card bordered={false}>
                        {PARTY_MASTER_FORM_ELEMENTS.map((element, index) => {
                            if (element.fieldType === MASTER_DATA_INDEX.FIELD_TYPE_SELECT) {
                                return getRowWithSelectElementJsx(element.label, element.name, element.options)
                            } else if (element.fieldType === MASTER_DATA_INDEX.FIELD_TYPE_RADIO) {
                                return getRowWithRadioElementJsx(element.label, element.name)
                            }
                            return getRowWithInputElementJsx(element.label, element.name)
                        })}
                    </Card>
                }
                {showModalDialogForm.form === LEFT_TABS.PARCEL_SHOP_MASTER_TABPANE &&
                    <Card bordered={false} id='parcel-shop-master-form-card'>
                        {PARCEL_SHOP_MASTER_FORM_ELEMENTS.map(element => getRowWithInputElementJsx(element.label, element.name))}
                    </Card>
                }
            </Modal>
        </div>
    )
}

export default AddEditFormModal
